def insert(root, key):
    if root is None:
        return TreeNode(key)
    if key < root.val:
        root.left = insert(root.left, key)
    else:
        root.right = insert(root.right, key)
    return root

# Construct BST
bst_root = TreeNode(50)
insert(bst_root, 30)
insert(bst_root, 70)
insert(bst_root, 20)

